customCss:
.single-summary-card-container {
            font-family: 'Noto Sans KR', sans-serif;
            display: flex;
            justify-content: center;
            align-items: center;
            padding: 20px 10px;
            background-color: #f8fafc;
            margin: 30px 0;
            border-radius: 12px;
            border: 1px solid #cbd5e1;
        }
        .single-summary-card {
            width: 100%;
            max-width: 700px;
            background-color: #ffffff;
            border-radius: 12px;
            padding: 25px;
            display: flex;
            flex-direction: column;
            box-sizing: border-box;
            height: auto;
        }
        .single-summary-card .card-header {
            display: flex;
            align-items: center;
            border-bottom: 2px solid #1e3a8a;
            padding-bottom: 12px;
            margin-bottom: 15px;
        }
        .single-summary-card .card-header-icon {
            font-size: 30px;
            color: #1e3a8a;
            margin-right: 12px;
        }
        .single-summary-card .card-header h3 {
            font-size: 22px;
            color: #1e3a8a;
            margin: 0;
            line-height: 1.3;
            font-weight: 700;
        }
        .single-summary-card .card-content {
            font-size: 15px;
            line-height: 1.6;
            color: #334155;
        }
        .single-summary-card .card-content .section {
            margin-bottom: 12px;
        }
        .single-summary-card .card-content strong {
            color: #1e3a8a;
            font-weight: 600;
        }
        .single-summary-card .card-content .highlight {
            background-color: #f1f5f9;
            padding: 2px 6px;
            border-radius: 4px;
            font-weight: bold;
            color: #0f172a;
        }
        .single-summary-card .card-content .formula {
            background-color: #f1f5f9;
            padding: 8px 12px;
            border-radius: 4px;
            font-size: 0.95em;
            text-align: center;
            margin-top: 5px;
            color: #1e293b;
            font-weight: bold;
            border: 1px solid #cbd5e1;
        }
        .single-summary-card .card-footer {
            font-size: 13px;
            color: #64748b;
            text-align: center;
            padding-top: 15px;
            border-top: 1px dashed #cbd5e1;
            margin-top: 15px;
        }

        @media (max-width: 768px) {
            .single-summary-card {
                padding: 18px;
            }
            .single-summary-card .card-header-icon {
                font-size: 26px;
            }
            .single-summary-card .card-header h3 {
                font-size: 18px;
            }
            .single-summary-card {
                font-size: 14px;
            }
            .single-summary-card .card-footer {
                font-size: 12px;
            }
        }
